//
// Component: Small Box
//

.small-box {
  @include border-radius($border-radius);
  @include box-shadow($lte-card-shadow);
  position: relative;
  display: block;
  margin-bottom: 1.25rem;
  --bs-link-color-rgb: none;
  --bs-link-hover-color-rgb: none;
  --bs-heading-color: none;

  // content wrapper
  > .inner {
    padding: 10px;
  }

  > .small-box-footer {
    position: relative;
    z-index: 10;
    display: block;
    padding: 3px 0;
    text-align: center;
    background-color: rgba($black, .07);

    &:hover {
      background-color: rgba($black, .1);
    }
  }

  h3 {
    @include font-size(2.2rem);
    padding: 0;
    margin: 0 0 10px;
    font-weight: 700;
    white-space: nowrap;
  }

  @include media-breakpoint-up(lg) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      h3 {
        @include font-size(1.6rem);
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      h3 {
        @include font-size(1.6rem);
      }
    }
  }

  @include media-breakpoint-up(xl) {
    .col-xl-2 &,
    .col-lg-2 &,
    .col-md-2 & {
      h3 {
        @include font-size(2.2rem);
      }
    }

    .col-xl-3 &,
    .col-lg-3 &,
    .col-md-3 & {
      h3 {
        @include font-size(2.2rem);
      }
    }
  }

  p {
    font-size: 1rem;

    > small {
      display: block;
      margin-top: 5px;
      font-size: .9rem;
      color: $gray-100;
    }
  }

  h3,
  p {
    z-index: 5;
  }

  // the icon
  .small-box-icon {
    position: absolute;
    top: 15px;
    right: 15px;
    z-index: 0;
    height: 70px;
    font-size: 70px;
    color: rgba($black, .15);
    @include transition(transform $lte-transition-speed linear);
  }

  // Small box hover state
  &:hover {
    // Animate icons on small box hover
    .small-box-icon {
      transform: scale(1.1);
    }
  }
}

@include media-breakpoint-down(sm) {
  // No need for icons on very small devices
  .small-box {
    text-align: center;

    .small-box-icon {
      display: none;
    }

    p {
      font-size: 12px;
    }
  }
}

@use "sass:color";

// Grid
.row.display {
  background: #eee;
  font-size: 11px;
  margin-bottom: 10px;
  line-height: 2rem;
  border: solid 1px #c6c6c6;
  margin-left: 0 !important;
  margin-right: 0 !important;

  .columns {
    &:nth-child(2),
    &.small-centered,
    &.large-centered {
      background: color.adjust(#eee, $lightness: -5%);
    }

    &.color-end {
      background: color.adjust(#eee, $lightness: -10%)
    }
  }
}

.row.display-end {
  background: #fff;
  font-size: 11px;
  margin-bottom: 10px;
  line-height: 2rem;
  border: solid 1px #c6c6c6;
  margin-left: 0 !important;
  margin-right: 0 !important;

  .columns {
    background: color.adjust(#eee, $lightness: -5%);
    border-left: 1px solid #c6c6c6;

    &.color-end {
      background: color.adjust(#eee, $lightness: -10%)
    }
  }
}

// Flex Grid
[id^="docs-flex"].docs-component .docs-code-live {
  @include foundation-flex-grid;

  .row {
    background: #f9f9f9;
    font-size: 11px;
    line-height: 2rem;
    border: solid 1px #c6c6c6;
    margin-left: 0;
    margin-right: 0;
    margin-bottom: 1.5rem;

    // Disable clearfix
    &::before,
    &::after {
      display: none;
    }
  }

  .column,
  .columns {
    float: none;
    width: auto;

    &:nth-child(odd) {
      background: #eee;
    }
    &:nth-child(even) {
      background: #ddd;
    }
  }
}

// XY Grid & Flexbox Utilities
[id^="docs-xy"].docs-component .docs-code-live,
[id^="docs-flexbox-utilities"].docs-component .docs-code-live {
  @include foundation-flex-grid;
  @include foundation-xy-grid-classes;

  .grid-x,
  .grid-y {
    background: color.adjust($primary-color, $lightness: 50%);
    font-size: 12px;
    line-height: 2rem;
    margin-bottom: 1.5rem;
  }

  .grid-y .grid-x {
    margin-bottom: 0;
  }

  .cell {
    &:nth-child(odd) {
      background: color.adjust($primary-color, $lightness: 30%);
      color: $black;
    }
    &:nth-child(even) {
      background: $primary-color;
      color: $white;
    }
  }
}

$button-responsive-expanded: true;

@import "./item-divider";
@import "./item-divider.ios.vars";

// iOS Item Divider
// --------------------------------------------------

:host {
  --background: #{$item-divider-ios-background};
  --color: #{$item-divider-ios-color};
  --padding-start: #{$item-divider-ios-padding-start};
  --inner-padding-end: #{$item-divider-ios-padding-end * 0.5};

  @include border-radius(0);

  position: relative;

  min-height: $item-divider-ios-min-height;

  font-size: $item-divider-ios-font-size;

  font-weight: $item-divider-ios-font-weight;
}


// iOS Item Divider Slots
// --------------------------------------------------

:host([slot="start"]) {
  @include margin($item-ios-slot-start-margin-top, $item-ios-slot-start-margin-end, $item-ios-slot-start-margin-bottom, $item-ios-slot-start-margin-start);
}

:host([slot="end"]) {
  @include margin($item-ios-slot-end-margin-top, $item-ios-slot-end-margin-end, $item-ios-slot-end-margin-bottom, $item-ios-slot-end-margin-start);
}

::slotted(ion-icon[slot="start"]),
::slotted(ion-icon[slot="end"]) {
  @include margin($item-ios-icon-slot-margin-top, $item-ios-icon-slot-margin-end, $item-ios-icon-slot-margin-bottom, $item-ios-icon-slot-margin-start);
}


// iOS Item Divider Content
// --------------------------------------------------

::slotted(h1) {
  @include margin(0, 0, 2px);
}

::slotted(h2) {
  @include margin(0, 0, 2px);
}

::slotted(h3),
::slotted(h4),
::slotted(h5),
::slotted(h6) {
  @include margin(0, 0, 3px);
}

::slotted(p) {
  @include margin($item-ios-paragraph-margin-top, $item-ios-paragraph-margin-end, $item-ios-paragraph-margin-bottom, $item-ios-paragraph-margin-start);

  color: $item-ios-paragraph-text-color;

  font-size: $item-ios-paragraph-font-size;

  line-height: normal;

  text-overflow: inherit;

  overflow: inherit;
}

::slotted(h2:last-child)
::slotted(h3:last-child),
::slotted(h4:last-child),
::slotted(h5:last-child),
::slotted(h6:last-child),
::slotted(p:last-child) {
  @include margin(null, null, 0, null);
}

// Sliders
// Credit: https://css-tricks.com/styling-cross-browser-compatible-range-inputs-css/
.slider {
  appearance: none;
  background: transparent;
  display: block;
  width: 100%;
  height: $unit-6;

  &:focus {
    @include control-shadow();
    outline: none;
  }

  &.tooltip:not([data-tooltip]) {
    &::after {
      content: attr(value);
    }
  }

  // Slider Thumb
  &::-webkit-slider-thumb {
    -webkit-appearance: none;
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    margin-top: -($unit-3 - $unit-h) / 2;
    transition: transform .2s;
    width: $unit-3;
  }
  &::-moz-range-thumb {
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    transition: transform .2s;
    width: $unit-3;
  }
  &::-ms-thumb {
    background: $primary-color;
    border: 0;
    border-radius: 50%;
    height: $unit-3;
    transition: transform .2s;
    width: $unit-3;
  }

  &:active {
    &::-webkit-slider-thumb {
      transform: scale(1.25);
    }
    &::-moz-range-thumb {
      transform: scale(1.25);
    }
    &::-ms-thumb {
      transform: scale(1.25);
    }
  }

  &:disabled,
  &.disabled {
    &::-webkit-slider-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
    &::-moz-range-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
    &::-ms-thumb {
      background: $gray-color-light;
      transform: scale(1);
    }
  }

  // Slider Track
  &::-webkit-slider-runnable-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-moz-range-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-ms-track {
    background: $bg-color-dark;
    border-radius: $border-radius;
    height: $unit-h;
    width: 100%;
  }
  &::-ms-fill-lower {
    background: $primary-color;
  }
}
